import React from 'react';
import './tabs.css';

// ─────────────────────────────────────────────────────────────
//  TYPES
// ─────────────────────────────────────────────────────────────

export type TabsVariant   = 'pills' | 'line' | 'enclosed' | 'solid' | 'soft';
export type TabsColor     = 'primary' | 'secondary' | 'danger' | 'success' | 'warning' | 'info';
export type TabsSize      = 'xs' | 'sm' | 'md' | 'lg' | 'xl';
export type TabsOrientation = 'horizontal' | 'vertical';

export interface TabItem {
  /** Unique key used as the value */
  value: string;

  /** Label text shown in the trigger */
  label: React.ReactNode;

  /** Icon rendered before the label */
  icon?: React.ReactNode;

  /** Badge count / label shown on the trigger */
  badge?: string | number;

  /** Disable this specific tab */
  disabled?: boolean;

  /** Content panel for this tab */
  content?: React.ReactNode;
}

export interface TabsProps {
  /** Tab definitions */
  tabs: TabItem[];

  /** Controlled active value */
  value?: string;

  /** Default active value (uncontrolled) */
  defaultValue?: string;

  /** Called when the active tab changes */
  onChange?: (value: string) => void;

  /** Visual style. Default: 'pills' */
  variant?: TabsVariant;

  /** Accent color. Default: 'primary' */
  color?: TabsColor;

  /** Size preset. Default: 'md' */
  size?: TabsSize;

  /** Horizontal or vertical layout. Default: 'horizontal' */
  orientation?: TabsOrientation;

  /** Stretch the tab list to full width */
  fullWidth?: boolean;

  /** Extra classes for the root element */
  className?: string;

  /** Extra classes for the tab list */
  listClassName?: string;

  /** Extra classes for every content panel */
  contentClassName?: string;
}

// ─────────────────────────────────────────────────────────────
//  CLASS BUILDER
// ─────────────────────────────────────────────────────────────

function buildRootClass(props: TabsProps): string {
  const {
    variant     = 'pills',
    color       = 'primary',
    size        = 'md',
    orientation = 'horizontal',
    className   = '',
  } = props;

  const classes = [
    'tabs-root',
    `tabs-${size}`,
    `tabs-variant-${variant}`,
    `tabs-color-${color}`,
    orientation === 'vertical' ? 'tabs-vertical' : '',
    className,
  ];

  return classes.filter(Boolean).join(' ');
}

// ─────────────────────────────────────────────────────────────
//  TABS
// ─────────────────────────────────────────────────────────────

function Tabs(props: TabsProps) {
  const {
    tabs,
    value        : controlledValue,
    defaultValue,
    onChange,
    variant      = 'pills',
    color        = 'primary',
    size         = 'md',
    orientation  = 'horizontal',
    fullWidth    = false,
    listClassName  = '',
    contentClassName = '',
  } = props;

  const isControlled = controlledValue !== undefined;
  const [internalValue, setInternalValue] = React.useState<string>(
    defaultValue ?? tabs.find(t => !t.disabled)?.value ?? ''
  );

  const activeValue = isControlled ? controlledValue! : internalValue;

  function activate(val: string) {
    if (!isControlled) setInternalValue(val);
    onChange?.(val);
  }

  // Keyboard navigation
  function handleKeyDown(e: React.KeyboardEvent, currentIndex: number) {
    const enabled = tabs.filter(t => !t.disabled);
    const ci      = enabled.findIndex(t => t.value === tabs[currentIndex].value);
    const isVert  = orientation === 'vertical';

    const prevKey = isVert ? 'ArrowUp'   : 'ArrowLeft';
    const nextKey = isVert ? 'ArrowDown' : 'ArrowRight';

    if (e.key === prevKey) {
      e.preventDefault();
      const prev = enabled[(ci - 1 + enabled.length) % enabled.length];
      activate(prev.value);
    } else if (e.key === nextKey) {
      e.preventDefault();
      const next = enabled[(ci + 1) % enabled.length];
      activate(next.value);
    } else if (e.key === 'Home') {
      e.preventDefault();
      activate(enabled[0].value);
    } else if (e.key === 'End') {
      e.preventDefault();
      activate(enabled[enabled.length - 1].value);
    }
  }

  const rootClass = buildRootClass(props);
  const listClass = [
    'tabs-list',
    fullWidth ? 'tabs-list-full' : '',
    listClassName,
  ].filter(Boolean).join(' ');

  return (
    <div className={rootClass}>
      {/* ── Tab list ── */}
      <div
        className={listClass}
        role="tablist"
        aria-orientation={orientation}
      >
        {tabs.map((tab, idx) => {
          const isActive   = tab.value === activeValue;
          const isDisabled = !!tab.disabled;

          return (
            <button
              key={tab.value}
              role="tab"
              type="button"
              id={`tab-trigger-${tab.value}`}
              aria-controls={`tab-panel-${tab.value}`}
              aria-selected={isActive}
              aria-disabled={isDisabled || undefined}
              data-state={isActive ? 'active' : 'inactive'}
              data-disabled={isDisabled || undefined}
              disabled={isDisabled}
              className="tabs-trigger"
              tabIndex={isActive ? 0 : -1}
              onClick={() => !isDisabled && activate(tab.value)}
              onKeyDown={(e) => handleKeyDown(e, idx)}
            >
              {tab.icon && (
                <span className="tabs-trigger-icon" aria-hidden="true">
                  {tab.icon}
                </span>
              )}
              {tab.label}
              {tab.badge !== undefined && (
                <span className="tabs-trigger-badge">{tab.badge}</span>
              )}
            </button>
          );
        })}
      </div>

      {/* ── Content panels ── */}
      {tabs.map(tab => (
        <div
          key={tab.value}
          role="tabpanel"
          id={`tab-panel-${tab.value}`}
          aria-labelledby={`tab-trigger-${tab.value}`}
          data-state={tab.value === activeValue ? 'active' : 'inactive'}
          tabIndex={0}
          className={['tabs-content', contentClassName].filter(Boolean).join(' ')}
        >
          {tab.content}
        </div>
      ))}
    </div>
  );
}

// ─────────────────────────────────────────────────────────────
//  COMPOSABLE SUB-COMPONENTS (for manual composition)
// ─────────────────────────────────────────────────────────────

interface TabsContextValue {
  activeValue : string;
  activate    : (v: string) => void;
  orientation : TabsOrientation;
}

const TabsContext = React.createContext<TabsContextValue>({
  activeValue : '',
  activate    : () => {},
  orientation : 'horizontal',
});

export interface TabsRootProps {
  value?        : string;
  defaultValue? : string;
  onChange?     : (value: string) => void;
  variant?      : TabsVariant;
  color?        : TabsColor;
  size?         : TabsSize;
  orientation?  : TabsOrientation;
  fullWidth?    : boolean;
  className?    : string;
  children      : React.ReactNode;
}

function TabsRoot({
  value        : controlledValue,
  defaultValue = '',
  onChange,
  variant      = 'pills',
  color        = 'primary',
  size         = 'md',
  orientation  = 'horizontal',
  fullWidth    = false,
  className    = '',
  children,
}: TabsRootProps) {
  const isControlled = controlledValue !== undefined;
  const [internalValue, setInternalValue] = React.useState(defaultValue);
  const activeValue = isControlled ? controlledValue! : internalValue;

  function activate(val: string) {
    if (!isControlled) setInternalValue(val);
    onChange?.(val);
  }

  const rootClass = [
    'tabs-root',
    `tabs-${size}`,
    `tabs-variant-${variant}`,
    `tabs-color-${color}`,
    orientation === 'vertical' ? 'tabs-vertical' : '',
    fullWidth ? 'tabs-list-full' : '',
    className,
  ].filter(Boolean).join(' ');

  return (
    <TabsContext.Provider value={{ activeValue, activate, orientation }}>
      <div className={rootClass}>{children}</div>
    </TabsContext.Provider>
  );
}

export interface TabsListProps {
  fullWidth?  : boolean;
  className?  : string;
  children    : React.ReactNode;
}

function TabsList({ fullWidth = false, className = '', children }: TabsListProps) {
  const { orientation } = React.useContext(TabsContext);
  const cls = ['tabs-list', fullWidth ? 'tabs-list-full' : '', className]
    .filter(Boolean).join(' ');
  return (
    <div className={cls} role="tablist" aria-orientation={orientation}>
      {children}
    </div>
  );
}

export interface TabsTriggerProps {
  value       : string;
  disabled?   : boolean;
  icon?       : React.ReactNode;
  badge?      : string | number;
  className?  : string;
  children    : React.ReactNode;
}

function TabsTrigger({
  value,
  disabled   = false,
  icon,
  badge,
  className  = '',
  children,
}: TabsTriggerProps) {
  const { activeValue, activate } = React.useContext(TabsContext);
  const isActive = value === activeValue;

  return (
    <button
      role="tab"
      type="button"
      id={`tab-trigger-${value}`}
      aria-controls={`tab-panel-${value}`}
      aria-selected={isActive}
      data-state={isActive ? 'active' : 'inactive'}
      data-disabled={disabled || undefined}
      disabled={disabled}
      tabIndex={isActive ? 0 : -1}
      className={['tabs-trigger', className].filter(Boolean).join(' ')}
      onClick={() => !disabled && activate(value)}
    >
      {icon && <span className="tabs-trigger-icon" aria-hidden="true">{icon}</span>}
      {children}
      {badge !== undefined && <span className="tabs-trigger-badge">{badge}</span>}
    </button>
  );
}

export interface TabsContentProps {
  value      : string;
  className? : string;
  children   : React.ReactNode;
}

function TabsContent({ value, className = '', children }: TabsContentProps) {
  const { activeValue } = React.useContext(TabsContext);
  return (
    <div
      role="tabpanel"
      id={`tab-panel-${value}`}
      aria-labelledby={`tab-trigger-${value}`}
      data-state={value === activeValue ? 'active' : 'inactive'}
      tabIndex={0}
      className={['tabs-content', className].filter(Boolean).join(' ')}
    >
      {children}
    </div>
  );
}

// ─────────────────────────────────────────────────────────────
//  useTab hook
// ─────────────────────────────────────────────────────────────

export function useTab(initial = '') {
  const [value, setValue] = React.useState(initial);
  return {
    value,
    onChange: (v: string) => setValue(v),
  };
}

export { Tabs, TabsRoot, TabsList, TabsTrigger, TabsContent };
export default Tabs;

/* ─────────────────────────────────────────────────────────────
   TABS — CSS
   Token / class-naming mirrors button.css & modal.css
   ───────────────────────────────────────────────────────────── */

:root {
  /* ── List (container for tab triggers) ── */
  --tab-list-bg           : #f1f5f9;
  --tab-list-radius       : 0.75rem;
  --tab-list-padding      : 0.25rem;
  --tab-list-gap          : 0.125rem;

  /* ── Trigger (individual tab button) ── */
  --tab-trigger-radius    : 0.5rem;
  --tab-trigger-color     : #64748b;
  --tab-trigger-font      : 0.875rem;
  --tab-trigger-weight    : 500;
  --tab-trigger-hover-bg  : rgba(255,255,255,0.6);
  --tab-trigger-hover-color: #1e293b;

  /* ── Active indicator ── */
  --tab-active-bg         : #ffffff;
  --tab-active-color      : #0f172a;
  --tab-active-weight     : 600;
  --tab-active-shadow     : 0 1px 4px rgba(15,23,42,0.10), 0 0 0 1px rgba(15,23,42,0.06);

  /* ── Content panel ── */
  --tab-content-radius    : 0.75rem;
  --tab-content-pad       : 1.5rem;

  /* ── Colors (active indicator accent) ── */
  --tab-color-primary  : #6366f1;
  --tab-color-secondary: #64748b;
  --tab-color-danger   : #ef4444;
  --tab-color-success  : #22c55e;
  --tab-color-warning  : #f59e0b;
  --tab-color-info     : #0ea5e9;

  /* ── Size tokens ── */
  --tab-h-xs : 1.75rem;
  --tab-h-sm : 2rem;
  --tab-h-md : 2.25rem;
  --tab-h-lg : 2.625rem;
  --tab-h-xl : 3rem;

  --tab-px-xs: 0.625rem;
  --tab-px-sm: 0.875rem;
  --tab-px-md: 1rem;
  --tab-px-lg: 1.25rem;
  --tab-px-xl: 1.5rem;

  --tab-fz-xs: 0.75rem;
  --tab-fz-sm: 0.8125rem;
  --tab-fz-md: 0.875rem;
  --tab-fz-lg: 0.9375rem;
  --tab-fz-xl: 1rem;
}

/* ══════════════════════════════════════════════════════════════
   VARIANT: pills (default)
   ══════════════════════════════════════════════════════════════ */

.tabs-root { display: flex; flex-direction: column; gap: 0; }

/* List */
.tabs-list {
  display         : inline-flex;
  align-items     : center;
  background      : var(--tab-list-bg);
  border-radius   : var(--tab-list-radius);
  padding         : var(--tab-list-padding);
  gap             : var(--tab-list-gap);
  width           : fit-content;
}

.tabs-list-full { width: 100%; }
.tabs-list-full .tabs-trigger { flex: 1; justify-content: center; }

/* Trigger */
.tabs-trigger {
  display         : inline-flex;
  align-items     : center;
  justify-content : center;
  gap             : 0.4rem;
  height          : var(--tab-h-md);
  padding         : 0 var(--tab-px-md);
  border          : none;
  border-radius   : var(--tab-trigger-radius);
  background      : transparent;
  color           : var(--tab-trigger-color);
  font-size       : var(--tab-fz-md);
  font-weight     : var(--tab-trigger-weight);
  white-space     : nowrap;
  cursor          : pointer;
  transition      : background 140ms, color 140ms, box-shadow 140ms;
  outline         : none;
  position        : relative;
  user-select     : none;
}
.tabs-trigger:hover {
  background : var(--tab-trigger-hover-bg);
  color      : var(--tab-trigger-hover-color);
}
.tabs-trigger:focus-visible {
  outline       : 2px solid var(--tab-color-primary);
  outline-offset: 2px;
}
.tabs-trigger[data-state="active"] {
  background : var(--tab-active-bg);
  color      : var(--tab-active-color);
  font-weight: var(--tab-active-weight);
  box-shadow : var(--tab-active-shadow);
}
.tabs-trigger[disabled],
.tabs-trigger[data-disabled] {
  opacity       : 0.45;
  cursor        : not-allowed;
  pointer-events: none;
}

/* Badge inside trigger */
.tabs-trigger-badge {
  display        : inline-flex;
  align-items    : center;
  justify-content: center;
  min-width      : 1.125rem;
  height         : 1.125rem;
  padding        : 0 0.3rem;
  border-radius  : 99px;
  font-size      : 0.6875rem;
  font-weight    : 600;
  background     : #e2e8f0;
  color          : #475569;
  line-height    : 1;
}
.tabs-trigger[data-state="active"] .tabs-trigger-badge {
  background: var(--tab-active-accent, var(--tab-color-primary));
  color     : #fff;
}

/* Icon wrap */
.tabs-trigger-icon { display: flex; align-items: center; flex-shrink: 0; }

/* Content panel */
.tabs-content {
  outline: none;
}
.tabs-content[data-state="inactive"] { display: none; }
.tabs-content[data-state="active"]   {
  animation: tabs-content-in 180ms ease;
}
@keyframes tabs-content-in {
  from { opacity: 0; transform: translateY(4px); }
  to   { opacity: 1; transform: translateY(0);   }
}

/* ── Size modifiers ── */
.tabs-xs .tabs-trigger { height: var(--tab-h-xs); padding: 0 var(--tab-px-xs); font-size: var(--tab-fz-xs); }
.tabs-sm .tabs-trigger { height: var(--tab-h-sm); padding: 0 var(--tab-px-sm); font-size: var(--tab-fz-sm); }
.tabs-md .tabs-trigger { height: var(--tab-h-md); padding: 0 var(--tab-px-md); font-size: var(--tab-fz-md); }
.tabs-lg .tabs-trigger { height: var(--tab-h-lg); padding: 0 var(--tab-px-lg); font-size: var(--tab-fz-lg); }
.tabs-xl .tabs-trigger { height: var(--tab-h-xl); padding: 0 var(--tab-px-xl); font-size: var(--tab-fz-xl); }

/* ── Color modifiers (accent on active) ── */
.tabs-color-primary   .tabs-trigger[data-state="active"] { color: var(--tab-color-primary);   --tab-active-accent: var(--tab-color-primary); }
.tabs-color-secondary .tabs-trigger[data-state="active"] { color: var(--tab-color-secondary); --tab-active-accent: var(--tab-color-secondary); }
.tabs-color-danger    .tabs-trigger[data-state="active"] { color: var(--tab-color-danger);    --tab-active-accent: var(--tab-color-danger); }
.tabs-color-success   .tabs-trigger[data-state="active"] { color: var(--tab-color-success);   --tab-active-accent: var(--tab-color-success); }
.tabs-color-warning   .tabs-trigger[data-state="active"] { color: var(--tab-color-warning);   --tab-active-accent: var(--tab-color-warning); }
.tabs-color-info      .tabs-trigger[data-state="active"] { color: var(--tab-color-info);      --tab-active-accent: var(--tab-color-info); }


/* ══════════════════════════════════════════════════════════════
   VARIANT: line (underline style)
   ══════════════════════════════════════════════════════════════ */

.tabs-variant-line .tabs-list {
  background    : transparent;
  border-radius : 0;
  padding       : 0;
  border-bottom : 2px solid #e2e8f0;
  gap           : 0;
  width         : fit-content;
}
.tabs-variant-line.tabs-list-full .tabs-list { width: 100%; }

.tabs-variant-line .tabs-trigger {
  border-radius : 0;
  background    : transparent !important;
  box-shadow    : none !important;
  padding-bottom: 0;
  position      : relative;
  margin-bottom : -2px;
}
.tabs-variant-line .tabs-trigger::after {
  content   : '';
  position  : absolute;
  bottom    : 0;
  left      : 50%;
  right     : 50%;
  height    : 2px;
  background: var(--tab-color-primary);
  border-radius: 99px 99px 0 0;
  transition: left 180ms ease, right 180ms ease;
}
.tabs-variant-line .tabs-trigger[data-state="active"]::after {
  left : 0;
  right: 0;
}
.tabs-variant-line.tabs-color-secondary .tabs-trigger::after { background: var(--tab-color-secondary); }
.tabs-variant-line.tabs-color-danger    .tabs-trigger::after { background: var(--tab-color-danger);    }
.tabs-variant-line.tabs-color-success   .tabs-trigger::after { background: var(--tab-color-success);   }
.tabs-variant-line.tabs-color-warning   .tabs-trigger::after { background: var(--tab-color-warning);   }
.tabs-variant-line.tabs-color-info      .tabs-trigger::after { background: var(--tab-color-info);      }


/* ══════════════════════════════════════════════════════════════
   VARIANT: enclosed (bordered card style)
   ══════════════════════════════════════════════════════════════ */

.tabs-variant-enclosed .tabs-list {
  background    : transparent;
  padding       : 0;
  border-radius : 0;
  border-bottom : 1px solid #e2e8f0;
  gap           : 0;
  width         : fit-content;
}
.tabs-variant-enclosed.tabs-list-full .tabs-list { width: 100%; }

.tabs-variant-enclosed .tabs-trigger {
  border-radius : 0.5rem 0.5rem 0 0;
  border        : 1px solid transparent;
  border-bottom : none;
  margin-bottom : -1px;
  background    : transparent !important;
  box-shadow    : none !important;
}
.tabs-variant-enclosed .tabs-trigger[data-state="active"] {
  background    : #fff !important;
  border-color  : #e2e8f0;
  border-bottom : 1px solid #fff !important;
}

/* ══════════════════════════════════════════════════════════════
   VARIANT: solid (button-group style)
   ══════════════════════════════════════════════════════════════ */

.tabs-variant-solid .tabs-list {
  background    : transparent;
  padding       : 0;
  border        : 1px solid #e2e8f0;
  border-radius : 0.625rem;
  overflow      : hidden;
  gap           : 0;
}
.tabs-variant-solid .tabs-trigger {
  border-radius : 0;
  border-right  : 1px solid #e2e8f0;
  background    : #fff !important;
  box-shadow    : none !important;
}
.tabs-variant-solid .tabs-trigger:last-child { border-right: none; }
.tabs-variant-solid .tabs-trigger[data-state="active"] {
  background : var(--tab-color-primary) !important;
  color      : #fff !important;
}
.tabs-variant-solid.tabs-color-secondary .tabs-trigger[data-state="active"] { background: var(--tab-color-secondary) !important; }
.tabs-variant-solid.tabs-color-danger    .tabs-trigger[data-state="active"] { background: var(--tab-color-danger)    !important; }
.tabs-variant-solid.tabs-color-success   .tabs-trigger[data-state="active"] { background: var(--tab-color-success)   !important; }
.tabs-variant-solid.tabs-color-warning   .tabs-trigger[data-state="active"] { background: var(--tab-color-warning)   !important; }
.tabs-variant-solid.tabs-color-info      .tabs-trigger[data-state="active"] { background: var(--tab-color-info)      !important; }


/* ══════════════════════════════════════════════════════════════
   VARIANT: soft (tinted active pill)
   ══════════════════════════════════════════════════════════════ */

.tabs-variant-soft .tabs-list {
  background: transparent;
  padding   : 0;
  gap       : 0.25rem;
}
.tabs-variant-soft .tabs-trigger {
  box-shadow: none !important;
}
.tabs-variant-soft .tabs-trigger[data-state="active"] {
  background: #eef2ff !important;
  color     : var(--tab-color-primary) !important;
}
.tabs-variant-soft.tabs-color-secondary .tabs-trigger[data-state="active"] { background: #f8fafc !important; color: var(--tab-color-secondary) !important; }
.tabs-variant-soft.tabs-color-danger    .tabs-trigger[data-state="active"] { background: #fef2f2 !important; color: var(--tab-color-danger)    !important; }
.tabs-variant-soft.tabs-color-success   .tabs-trigger[data-state="active"] { background: #f0fdf4 !important; color: var(--tab-color-success)   !important; }
.tabs-variant-soft.tabs-color-warning   .tabs-trigger[data-state="active"] { background: #fffbeb !important; color: var(--tab-color-warning)   !important; }
.tabs-variant-soft.tabs-color-info      .tabs-trigger[data-state="active"] { background: #f0f9ff !important; color: var(--tab-color-info)      !important; }


/* ══════════════════════════════════════════════════════════════
   Vertical orientation
   ══════════════════════════════════════════════════════════════ */

.tabs-vertical {
  flex-direction: row;
  align-items   : flex-start;
  gap           : 1.25rem;
}
.tabs-vertical .tabs-list {
  flex-direction : column;
  height         : fit-content;
  width          : auto;
  min-width      : 10rem;
}
.tabs-vertical .tabs-list-full { height: 100%; }
.tabs-vertical .tabs-trigger   { justify-content: flex-start; width: 100%; }

.tabs-vertical.tabs-variant-line .tabs-list {
  border-bottom : none;
  border-right  : 2px solid #e2e8f0;
}
.tabs-vertical.tabs-variant-line .tabs-trigger::after {
  bottom: 0; top: 0;
  left  : auto; right: 0;
  width : 2px; height: auto;
  border-radius: 99px 0 0 99px;
  transition: top 180ms ease, bottom 180ms ease;
}
.tabs-vertical.tabs-variant-line .tabs-trigger[data-state="active"]::after {
  top: 0; bottom: 0; left: auto; right: 0;
}
